async fn relate(
        &self,
        from: &Uuid,
        relation: &str,
        to: &Uuid,
        metadata: Option<serde_json::Value>,
    ) -> Result<()> {
        sqlx::query(
            "INSERT INTO edges (from_id, relation, to_id, metadata) \
             VALUES ($1, $2, $3, $4) ON CONFLICT DO NOTHING",
        )
        .bind(from)
        .bind(relation)
        .bind(to)
        .bind(&metadata)
        .execute(&self.pool)
        .await
        .map_err(|e| CorviaError::Storage(format!("Failed to create edge: {e}")))?;

        Ok(())
    }
